// safeRedirectRe strips redirect forms that are not writes:
// - N>/dev/null or >>/dev/null  (discard output)
// - N>&M                        (fd-to-fd, e.g. 2>&1)
var (
	safeRedirectRe   = regexp.MustCompile(`\d*>>?\s*/dev/null|\d*>&\d*`)
	singleQuotedRe   = regexp.MustCompile(`'[^']*'`)
